import numpy as np
import hashlib
from typing import List

class ChallengeSampler:
    def __init__(self, n: int = 256, tau: int = 39):
        self.n = n
        self.tau = tau

    def sample_challenge(self, seed: bytes) -> np.ndarray:
        c = np.zeros(self.n, dtype=np.int32)

        # Use SHAKE-256 for expandable output
        # Simplified: use SHA3-256 repeatedly
        used_positions = set()
        counter = 0

        while len(used_positions) < self.tau:
            # Generate deterministic randomness
            h = hashlib.sha3_256(seed + counter.to_bytes(4, 'big')).digest()

            # Extract position (8 bits, may need multiple)
            for i in range(0, len(h) - 1, 2):
                if len(used_positions) >= self.tau:
                    break

                pos = h[i] % self.n
                if pos not in used_positions:
                    used_positions.add(pos)
                    sign = 1 if (h[i+1] & 1) == 0 else -1
                    c[pos] = sign

            counter += 1

        return c

    def verify_challenge(self, c: np.ndarray) -> bool:
        non_zero = c[c != 0]

        # Check count
        if len(non_zero) != self.tau:
            return False

        # Check values are ±1
        if not np.all(np.abs(non_zero) == 1):
            return False

        return True

    def challenge_weight(self, c: np.ndarray) -> int:
        return np.sum(c != 0)
